// Physical memory layout

#ifdef __loongarch__

// qemu-system-loongarch64 virt machine memory map
//
// 0x00000000 -- start of physical RAM
// 0x00200000 -- kernel loaded here by -kernel
// 0x10000000 -- LS7A PCH-PIC registers
// 0x1c000000 -- BIOS ROM
// 0x1fe001e0 -- uart16550 serial port

#define DMWIN_MASK 0x9000000000000000UL

// qemu puts UART registers here in virtual memory (DMW window).
#define UART0 (0x1fe001e0UL | DMWIN_MASK)
#define UART0_IRQ 2

// virtio is PCI-based on LoongArch, not MMIO.
// virtio_mmio addresses below are RISC-V only.

/* ============== LS7A registers =============== */
#define LS7A_PCH_REG_BASE       (0x10000000UL | DMWIN_MASK)

#define LS7A_INT_MASK_REG       (LS7A_PCH_REG_BASE + 0x020)
#define LS7A_INT_EDGE_REG       (LS7A_PCH_REG_BASE + 0x060)
#define LS7A_INT_CLEAR_REG      (LS7A_PCH_REG_BASE + 0x080)
#define LS7A_INT_HTMSI_VEC_REG  (LS7A_PCH_REG_BASE + 0x200)
#define LS7A_INT_STATUS_REG     (LS7A_PCH_REG_BASE + 0x3a0)
#define LS7A_INT_POL_REG        (LS7A_PCH_REG_BASE + 0x3e0)

// the kernel expects there to be RAM
// for use by user pages
// from physical address 0x0 to 128MB, mapped via DMW.
#define KERNBASE 0x9000000000000000UL
#define PHYSTOP (KERNBASE + 128*1024*1024)

#else // __riscv

// qemu -machine virt is set up like this,
// based on qemu's hw/riscv/virt.c:
//
// 00001000 -- boot ROM, provided by qemu
// 02000000 -- CLINT
// 0C000000 -- PLIC
// 10000000 -- uart0
// 10001000 -- virtio disk
// 80000000 -- qemu's boot ROM loads the kernel here,
//             then jumps here.
// unused RAM after 80000000.

// the kernel uses physical memory thus:
// 80000000 -- entry.S, then kernel text and data
// end -- start of kernel page allocation area
// PHYSTOP -- end RAM used by the kernel

// qemu puts UART registers here in physical memory.
#define UART0 0x10000000L
#define UART0_IRQ 10

// virtio mmio interface
#define VIRTIO0 0x10001000
#define VIRTIO1 0x10002000  // Second virtio device
#define VIRTIO2 0x10003000  // Third virtio device
#define VIRTIO3 0x10004000  // Fourth virtio device
#define VIRTIO0_IRQ 1
#define VIRTIO1_IRQ 2
#define VIRTIO2_IRQ 3
#define VIRTIO3_IRQ 4

// qemu puts platform-level interrupt controller (PLIC) here.
#define PLIC 0x0c000000L
#define PLIC_PRIORITY (PLIC + 0x0)
#define PLIC_PENDING (PLIC + 0x1000)
#define PLIC_SENABLE(hart) (PLIC + 0x2080 + (hart)*0x100)
#define PLIC_SPRIORITY(hart) (PLIC + 0x201000 + (hart)*0x2000)
#define PLIC_SCLAIM(hart) (PLIC + 0x201004 + (hart)*0x2000)

// the kernel expects there to be RAM
// for use by the kernel and user pages
// from physical address 0x80000000 to PHYSTOP.
#define KERNBASE 0x80000000L
#define PHYSTOP (KERNBASE + 128*1024*1024)

#endif

// map the trampoline page to the highest address,
// in both user and kernel space.
#define TRAMPOLINE (MAXVA - PGSIZE)

// map kernel stacks beneath the trampoline,
// each surrounded by invalid guard pages.
#define KSTACK(p) (TRAMPOLINE - ((p)+1)* 2*PGSIZE)

// User memory layout.
// Address zero first:
//   text
//   original data and bss
//   fixed-size stack
//   expandable heap
//   ...
//   invalid guard page
//   KSTACK (used for kernel thread)
//   TRAPFRAME (p->trapframe, used by the uservec)
//   TRAMPOLINE (the same page as in the kernel)
#define TRAPFRAME (TRAMPOLINE - PGSIZE)

