    return -1;
  if(copyin(myproc()->pagetable, (char *)&req, reqaddr, sizeof(req)) < 0)
    return -1;
  waitticks = req.sec * 10 + (req.nsec + 99999999) / 100000000;
  if(waitticks == 0 && (req.sec || req.nsec))
    waitticks = 1;
