{
  struct file *f;
  int fd, cmd, arg;
  int newfd;

  argint(1, &cmd);
  argint(2, &arg);
  if(argfd(0, &fd, &f) < 0)
    return -1;

  switch(cmd){
  case F_DUPFD:
  case F_DUPFD_CLOEXEC:
    if((newfd = fdalloc_from(f, arg)) < 0)
      return -1;
    filedup(f);
    return newfd;
  case F_GETFD:
    return 0;
  case F_SETFD:
    return 0;
  case F_GETFL:
    return (f->readable && f->writable) ? O_RDWR :
           (f->writable ? O_WRONLY : O_RDONLY);
  case F_SETFL:
    return 0;
  default:
    return 0;
  }
}

