int
ext4_read_sb(int dev)
{
    struct buf *sb;
    struct ext4_super_block *es;
    uint32 blocksize;



    sb = bread(dev, 1);
    es = (struct ext4_super_block *)sb->data;

    if (es->s_magic != EXT4_SUPERBLOCK_MAGIC) {
        brelse(sb);
        esbi[dev].ext4_detected = 0;
        return -1;
    }

    blocksize = 1024 << es->s_log_block_size;
    esbi[dev].blocksize = blocksize;
    esbi[dev].blocks_per_group = es->s_blocks_per_group;
    esbi[dev].inodes_per_group = es->s_inodes_per_group;
    esbi[dev].inodes_count = es->s_inodes_count;
    esbi[dev].blocks_count = es->s_blocks_count_lo;
    esbi[dev].first_ino = es->s_first_ino;
    esbi[dev].inode_size = es->s_inode_size;
    esbi[dev].sb_block = 1;
    esbi[dev].s_first_data_block = es->s_first_data_block;

    if (esbi[dev].blocksize == 1024) {
        esbi[dev].group_desc_block = 2;
    } else {
        esbi[dev].group_desc_block = 1;
    }

    esbi[dev].num_groups = (esbi[dev].blocks_count + esbi[dev].blocks_per_group - 1) / esbi[dev].blocks_per_group;
    esbi[dev].group_desc_size = sizeof(struct ext4_group_desc);
    esbi[dev].ext4_detected = 1;
    ext4_init_meta_lock();

    // printf("EXT4 detected: blocksize=%d blocks=%d inodes=%d groups=%d\n",
    //        esbi[dev].blocksize, esbi[dev].blocks_count, esbi[dev].inodes_count, esbi[dev].num_groups);

    brelse(sb);
    return 0;
}

