static uint
ext4_inode_table_block(int dev, uint group)
{
    char *buf;
    struct ext4_group_desc *desc;
    uint block;
    uint group_desc_blockno;
    uint offset;

    // Calculate the block number and offset for this group's descriptor
    offset = group * esbi[dev].group_desc_size;
    group_desc_blockno = esbi[dev].group_desc_block + offset / esbi[dev].blocksize;
    offset = offset % esbi[dev].blocksize;

    buf = kalloc();
    if (!buf)
        return 0;
    ext4_read_full_block(dev, group_desc_blockno, buf);
    desc = (struct ext4_group_desc *)(buf + offset);
    block = desc->bg_inode_table_lo;
    kfree(buf);

    // Return logical block number (ext4_read_full_block will convert to sector)
    return block;
}

// 从磁盘读取指定inode号的inode结构体
// dev: 设备号
// ino: inode号（从1开始）
// einode: 输出参数，用于存储读取到的inode结构体
// 返回值: 成功返回0，失败返回-1
int
ext4_iread(int dev, uint ino, struct ext4_inode *einode)
{
    // printf("-------size of ext4_inode: %ld\n", sizeof(struct ext4_inode));
    uint group, block, offset;
    char *buf;
    struct ext4_inode *inode;

    // 检查inode号是否有效（inode号从1开始）
    if (ino < 1 || ino > esbi[dev].inodes_count) {
        return -1;
    }

    // 计算inode所在的块组号
    group = ext4_inode_group(ino, dev);
    // 获取该块组的inode表起始块号
    block = ext4_inode_table_block(dev, group);

    // 计算inode在inode表中的字节偏移量
    offset = ((ino - 1) % esbi[dev].inodes_per_group) * esbi[dev].inode_size;
    // 根据偏移量计算inode所在的物理块号（相对于inode表起始块）
    block += offset / esbi[dev].blocksize;
    // 计算inode在块内的字节偏移量
    offset = offset % esbi[dev].blocksize;

    // 分配临时缓冲区用于读取磁盘块
    buf = kalloc();
    if (!buf)
        return -1;
    // 读取包含目标inode的完整块
    ext4_read_full_block(dev, block, buf);

    // 根据块内偏移量定位到目标inode结构体
    inode = (struct ext4_inode *)(buf + offset);
    // 将inode数据复制到输出参数
    memmove(einode, inode, sizeof(struct ext4_inode));
    // 释放临时缓冲区
    kfree(buf);

    return 0;
}

static int
ext4_iwrite_locked(int dev, uint ino, struct ext4_inode *einode)
{
    uint group, block, offset;
    char *buf;
    struct ext4_inode *inode;

    if (ino < EXT4_ROOT_INO || ino > esbi[dev].inodes_count)
        return -1;

    group = ext4_inode_group(ino, dev);
    block = ext4_inode_table_block(dev, group);

    offset = ((ino - 1) % esbi[dev].inodes_per_group) * esbi[dev].inode_size;
    block += offset / esbi[dev].blocksize;
    offset = offset % esbi[dev].blocksize;

    buf = kalloc();
    if (!buf)
        return -1;

    ext4_read_full_block(dev, block, buf);
    inode = (struct ext4_inode *)(buf + offset);
    memmove(inode, einode, sizeof(struct ext4_inode));

    ext4_write_full_block(dev, block, buf);

    kfree(buf);
    return 0;
}

