// yyh comment : 
// 1. kalloc() 只给一页，未必够 ext4 blocksize
// 2. ext4_bmap() 返回 0 时直接分配块，但只处理 direct block
// 3. 删除大小限制，允许写入任意位置
// 4. bp 的写回逻辑依赖 blocksize 是 BSIZE 的整数倍

int
ext4_writei(struct inode *ip, int user_src, uint64 src, uint off, uint n)
{
    uint dev = ip->dev;
    struct ext4_inode einode;
    uint blk, off_in_blk;
    int tot = 0;
    int has_extents;

    if (ext4_iread(dev, ip->inum, &einode) < 0)
        return -1;

    has_extents = (einode.i_flags & EXT4_EXTENTS_FL) != 0;

    // Keep xv6 semantics: writes may extend EOF, but they may not start
    // beyond the current size.
    if (off > ip->size || off + n < off)
        return -1;
    if (off + n > MAXFILE * BSIZE)
        return -1;

    // 删除大小限制，允许写入任意位置

    while (tot < n) {
        blk = ext4_bmap(ip, off / esbi[dev].blocksize);

        if (blk == 0) {
            if (has_extents) {
                if (tot == 0)
                    return -1;
                break;
            }
            blk = ext4_alloc_block(dev);
            if (blk == (uint)-1)
                break;

            uint log_blk_idx = off / esbi[dev].blocksize;
            if (log_blk_idx < EXT4_NDIR_BLOCKS) {
                einode.i_block[log_blk_idx] = blk;
                ip->addrs[log_blk_idx] = blk;
            } else if (log_blk_idx < EXT4_NDIR_BLOCKS + NINDIRECT) {
                char *ind_buf;
                uint *indirect;
                uint ind_idx = log_blk_idx - EXT4_NDIR_BLOCKS;

                ind_buf = kalloc();
                if (!ind_buf)
                    break;

                if (einode.i_block[EXT4_IND_BLOCK] == 0) {
                    uint ind_blk = ext4_alloc_block(dev);
                    if (ind_blk == (uint)-1) {
                        kfree(ind_buf);
                        break;
                    }
                    memset(ind_buf, 0, esbi[dev].blocksize);
                    ext4_write_full_block(dev, ind_blk, ind_buf);
                    einode.i_block[EXT4_IND_BLOCK] = ind_blk;
                    ip->addrs[NDIRECT] = ind_blk;
                } else {
                    ext4_read_full_block(dev, einode.i_block[EXT4_IND_BLOCK], ind_buf);
                }

                indirect = (uint *)ind_buf;
                indirect[ind_idx] = blk;
                ext4_write_full_block(dev, einode.i_block[EXT4_IND_BLOCK], ind_buf);
                kfree(ind_buf);
            } else {
                break;
            }
        }

        // 用 kalloc + ext4_read_full_block 替代 ext4_read_block
        char *write_buf = kalloc();
        if (!write_buf) break;
        ext4_read_full_block(dev, blk, write_buf);

        off_in_blk = off % esbi[dev].blocksize;
        uint m = min(n - tot, esbi[dev].blocksize - off_in_blk);

        // if (user_src) {
        //     either_copyin(write_buf + off_in_blk, user_src, src + tot, m);
        // } else {
        //     memmove(write_buf + off_in_blk, (void *)(src + tot), m);
        // }

        // yyh comment :
        // 两个不太对的点，copyin 要检查返回的东西，不能直接call完就不管了
        // 其次either_copyin本来就会看是不是用户态发来的东西，所以没必要在这里再打一个if
        // 修改如下
        if (either_copyin(write_buf + off_in_blk, user_src, src + tot, m) < 0) {
            kfree(write_buf);
            break;
        }

        // Write back the whole block in one request
        ext4_write_full_block(dev, blk, write_buf);
        kfree(write_buf);

        tot += m;
        off += m;
    }

    if (off > einode.i_size_lo)
        einode.i_size_lo = off;

    einode.i_mtime = einode.i_ctime = 0;
    ext4_iwrite(dev, ip->inum, &einode);
    if (!has_extents)
        memmove(ip->addrs, einode.i_block, sizeof(ip->addrs));
    ip->size = einode.i_size_lo;

    return tot;
}

