// handle an interrupt, exception, or system call from user space.
// called from uservec.S
//
void
usertrap(void)
{
  int which_dev = 0;

  if((r_csr_prmd() & PRMD_PPLV) == 0)
    panic("usertrap: not from user mode");

  // send interrupts and exceptions to kerneltrap(),
  // since we're now in the kernel.
  w_csr_eentry((uint64)kernelvec);

  struct proc *p = myproc();

  // save user program counter.
  p->trapframe->epc = r_csr_era();

  uint32 ecode = (r_csr_estat() & CSR_ESTAT_ECODE) >> 16;
  if(ecode == 0xb || ecode == 0xc || ecode == 0xd){
    // system call

    if(killed(p))
      kexit(-1);

    // era points to the syscall instruction,
    // but we want to return to the next instruction.
    p->trapframe->epc += 4;

    // an interrupt will change crmd & prmd registers,
    // so don't enable until done with those registers.
    intr_on();

