  }

  // give up the CPU if this is a timer interrupt.
  if(which_dev == 2 && myproc() != 0 && myproc()->state == RUNNING)
    yield();

  // the yield() may have caused some traps to occur,
  // so restore trap registers for use by kernelvec.S's instruction.
  w_csr_era(era);
  w_csr_prmd(prmd);
}

void
machine_trap()
{
  panic("machine error");
}

void
clockintr()
{
  acquire(&tickslock);
  ticks++;
  wakeup(&ticks);
  release(&tickslock);
}

// check if it's an external interrupt or software interrupt,
// and handle it.
// returns 2 if timer interrupt,
// 1 if other device,
// 0 if not recognized.
int
devintr()
{
  uint32 estat = r_csr_estat();
  uint32 ecfg = r_csr_ecfg();

  if(estat & ecfg & HWI_VEC) {
    // this is a hardware interrupt, via IOCSR.

    // irq indicates which device interrupted.
    uint64 irq = extioi_claim();
    if(irq & (1UL << UART0_IRQ)){
      uartintr();
      extioi_complete(1UL << UART0_IRQ);
    } else if(irq & (0xFUL << 16)){
      // PCI INTx interrupts (irqs 16-19)
      virtio_disk_intr();
      apic_complete(irq & (0xFUL << 16));
      extioi_complete(irq & (0xFUL << 16));
    } else if(irq){
      printf("unexpected interrupt irq=%ld\n", irq);
      apic_complete(irq);
      extioi_complete(irq);
    }

    return 1;
  } else if(estat & ecfg & TI_VEC){
    // timer interrupt

    if(cpuid() == 0){
      clockintr();
    }

    // acknowledge the timer interrupt by clearing
    // the TI bit in TICLR.
    w_csr_ticlr(r_csr_ticlr() | CSR_TICLR_CLR);

    return 2;
  } else {
    return 0;
  }
}

// File system implementation.  Five layers:
//   + Blocks: allocator for raw disk blocks.
//   + Log: crash recovery for multi-step updates.
//   + Files: inode allocator, reading, writing, metadata.
//   + Directories: inode with special contents (list of other inodes!)
//   + Names: paths like /usr/rtm/xv6/fs.c for convenient naming.
//
// This file contains the low-level file system manipulation
// routines.  The (higher-level) system call implementations
// are in sysfile.c.

#include "types.h"
#include "arch.h"
#include "defs.h"
#include "param.h"
#include "stat.h"
#include "spinlock.h"
#include "proc.h"
#include "sleeplock.h"
#include "fs.h"
#include "buf.h"
#include "file.h"
#include "ext4.h"

// EXT4 file mode constants
#define EXT4_S_IFMT   0xF000  // File type mask
#define EXT4_S_IFSOCK 0xC000  // Socket
#define EXT4_S_IFLNK  0xA000  // Symbolic link
#define EXT4_S_IFREG  0x8000  // Regular file
#define EXT4_S_IFBLK  0x6000  // Block device
#define EXT4_S_IFDIR  0x4000  // Directory
#define EXT4_S_IFCHR  0x2000  // Character device
#define EXT4_S_IFIFO  0x1000  // FIFO

#define min(a, b) ((a) < (b) ? (a) : (b))
// there should be one superblock per disk device
struct superblock sb[NDEV];  // Array of superblocks for each device 

// Read the super block.
static void
readsb(int dev, struct superblock *sb)
{
  struct buf *bp;

  bp = bread(dev, 1);
  memmove(sb, bp->data, sizeof(*sb));
  brelse(bp);
}

// Init fs
void
fsinit(int dev) {
  struct buf *sb_buf;

  // ext4 superblock is always at offset 1024 bytes from start of partition
  // With BSIZE=1024, bread(dev, 1) reads sector 1*2=2, offset 1024 bytes
  sb_buf = bread(dev, 1);
  struct ext4_super_block *es = (struct ext4_super_block *)sb_buf->data;

  if (es->s_magic == EXT4_SUPERBLOCK_MAGIC) {
    uint32 s_log_block_size = es->s_log_block_size;
    uint32 block_size = 1024 << s_log_block_size;
    // printf("Detected EXT4! block_size = %d (s_log_block_size = %d)\n", block_size, s_log_block_size);

    // Initialize esbi from the superblock
    esbi[dev].blocksize = block_size;
    esbi[dev].blocks_per_group = es->s_blocks_per_group;
    esbi[dev].inodes_per_group = es->s_inodes_per_group;
    esbi[dev].inodes_count = es->s_inodes_count;
    esbi[dev].blocks_count = es->s_blocks_count_lo;
    esbi[dev].first_ino = es->s_first_ino;
    esbi[dev].inode_size = es->s_inode_size;
    esbi[dev].sb_block = 1;
    esbi[dev].s_first_data_block = es->s_first_data_block;

    if (esbi[dev].blocksize == 1024) {
        esbi[dev].group_desc_block = 2;
    } else {
        esbi[dev].group_desc_block = 1;
    }

    esbi[dev].num_groups = (esbi[dev].blocks_count + esbi[dev].blocks_per_group - 1) / esbi[dev].blocks_per_group;
    esbi[dev].group_desc_size = sizeof(struct ext4_group_desc);
    esbi[dev].ext4_detected = 1;

    // printf("EXT4 detected: blocksize=%d blocks=%d inodes=%d groups=%d\n",
    //        esbi[dev].blocksize, esbi[dev].blocks_count, esbi[dev].inodes_count, esbi[dev].num_groups);

    if (ext4_mount(dev) < 0) {
      panic("failed to mount EXT4");
    }
    brelse(sb_buf);
    return;
  }
  brelse(sb_buf);

  // Fall back to SFS
  readsb(dev, &sb[dev]);
  if(sb[dev].magic != FSMAGIC)
    panic("invalid file system");
  initlog(dev, &sb[dev]);
  ireclaim(dev);
}

// Zero a block.
static void
bzero(int dev, int bno)
{
  struct buf *bp;

  bp = bread(dev, bno);
  memset(bp->data, 0, BSIZE);
  log_write(bp);
  brelse(bp);
}

// Blocks.

// Allocate a zeroed disk block.
// returns 0 if out of disk space.
static uint
balloc(uint dev)
{
  int b, bi, m;
  struct buf *bp;

  bp = 0;
  for(b = 0; b < sb[dev].size; b += BPB){
    bp = bread(dev, BBLOCK(b, sb[dev]));
    for(bi = 0; bi < BPB && b + bi < sb[dev].size; bi++){
      m = 1 << (bi % 8);
      if((bp->data[bi/8] & m) == 0){  // Is block free?
        bp->data[bi/8] |= m;  // Mark block in use.
        log_write(bp);
        brelse(bp);
        bzero(dev, b + bi);
        return b + bi;
      }
    }
    brelse(bp);
  }
  // printf("balloc: out of blocks\n");
  return 0;
}

// Free a disk block.
static void
bfree(int dev, uint b)
{
  struct buf *bp;
  int bi, m;

  bp = bread(dev, BBLOCK(b, sb[dev]));
  bi = b % BPB;
  m = 1 << (bi % 8);
  if((bp->data[bi/8] & m) == 0)
    panic("freeing free block");
  bp->data[bi/8] &= ~m;
  log_write(bp);
  brelse(bp);
}

// Inodes.
//
// An inode describes a single unnamed file.
// The inode disk structure holds metadata: the file's type,
// its size, the number of links referring to it, and the
// list of blocks holding the file's content.
//
// The inodes are laid out sequentially on disk at block
// sb.inodestart. Each inode has a number, indicating its
// position on the disk.
//
// The kernel keeps a table of in-use inodes in memory
// to provide a place for synchronizing access
// to inodes used by multiple processes. The in-memory
// inodes include book-keeping information that is
// not stored on disk: ip->ref and ip->valid.
//
// An inode and its in-memory representation go through a
// sequence of states before they can be used by the
// rest of the file system code.
//
// * Allocation: an inode is allocated if its type (on disk)
//   is non-zero. ialloc() allocates, and iput() frees if
//   the reference and link counts have fallen to zero.
//
// * Referencing in table: an entry in the inode table
//   is free if ip->ref is zero. Otherwise ip->ref tracks
//   the number of in-memory pointers to the entry (open
//   files and current directories). iget() finds or
//   creates a table entry and increments its ref; iput()
//   decrements ref.
//
// * Valid: the information (type, size, &c) in an inode
//   table entry is only correct when ip->valid is 1.
//   ilock() reads the inode from
//   the disk and sets ip->valid, while iput() clears
//   ip->valid if ip->ref has fallen to zero.
//

//
// Support functions for system calls that involve file descriptors.
//

#include "types.h"
#include "arch.h"
#include "defs.h"
#include "param.h"
#include "fs.h"
#include "spinlock.h"
#include "sleeplock.h"
#include "file.h"
#include "stat.h"
#include "proc.h"

struct devsw devsw[NDEV];
struct {
  struct spinlock lock;
  struct file file[NFILE];
} ftable;

void
fileinit(void)
{
  initlock(&ftable.lock, "ftable");
}

// Allocate a file structure.
struct file*
filealloc(void)
{
  struct file *f;

  acquire(&ftable.lock);
  for(f = ftable.file; f < ftable.file + NFILE; f++){
    if(f->ref == 0){
      f->ref = 1;
      release(&ftable.lock);
      return f;
    }
  }
  release(&ftable.lock);
  return 0;
}

// Increment ref count for file f.
struct file*
filedup(struct file *f)
{
  acquire(&ftable.lock);
  if(f->ref < 1)
    panic("filedup");
  f->ref++;
  release(&ftable.lock);
  return f;
}

// Close file f.  (Decrement ref count, close when reaches 0.)
void
fileclose(struct file *f)
{
  struct file ff;

  acquire(&ftable.lock);
  if(f->ref < 1)
    panic("fileclose");
  if(--f->ref > 0){
    release(&ftable.lock);
    return;
  }
  ff = *f;
  f->ref = 0;
  f->type = FD_NONE;
  release(&ftable.lock);

  if(ff.type == FD_PIPE){
    pipeclose(ff.pipe, ff.writable);
  } else if(ff.type == FD_INODE || ff.type == FD_DEVICE){
    begin_op();
    iput(ff.ip);
    end_op();
  }
}

// Get metadata about file f.
// addr is a user virtual address, pointing to a struct stat.
int
filestat(struct file *f, uint64 addr)
{
  struct proc *p = myproc();
  struct stat st;

  if(f->type == FD_INODE || f->type == FD_DEVICE){
    ilock(f->ip);
    stati(f->ip, &st);
    iunlock(f->ip);
    if(copyout(p->pagetable, addr, (char *)&st, sizeof(st)) < 0)
      return -1;
    return 0;
  }
  return -1;
}

// Read from file f.
// addr is a user virtual address.
int
fileread(struct file *f, uint64 addr, int n)
{
  int r = 0;

  if(f->readable == 0)
    return -1;

  if(f->type == FD_PIPE){
    r = piperead(f->pipe, addr, n);
  } else if(f->type == FD_DEVICE){
    if(f->major < 0 || f->major >= NDEV || !devsw[f->major].read)
      return -1;
    r = devsw[f->major].read(1, addr, n);
  } else if(f->type == FD_INODE){
    ilock(f->ip);
    if((r = readi(f->ip, 1, addr, f->off, n)) > 0)
      f->off += r;
    iunlock(f->ip);
  } else {
    panic("fileread");
  }

  return r;
}

// Write to file f.
// addr is a user virtual address.
int
filewrite(struct file *f, uint64 addr, int n)
{
  int r, ret = 0;

  if(f->writable == 0)
    return -1;

  if(f->type == FD_PIPE){
    ret = pipewrite(f->pipe, addr, n);
  } else if(f->type == FD_DEVICE){
    if(f->major < 0 || f->major >= NDEV || !devsw[f->major].write)
      return -1;
    ret = devsw[f->major].write(1, addr, n);
  } else if(f->type == FD_INODE){
    // write a few blocks at a time to avoid exceeding
    // the maximum log transaction size, including
    // i-node, indirect block, allocation blocks,
    // and 2 blocks of slop for non-aligned writes.
    int max = ((MAXOPBLOCKS-1-1-2) / 2) * BSIZE;
    int i = 0;
    while(i < n){
      int n1 = n - i;
      if(n1 > max)
        n1 = max;

      begin_op();
      ilock(f->ip);
      if(f->append)
        f->off = f->ip->size;
      if ((r = writei(f->ip, 1, addr + i, f->off, n1)) > 0)
        f->off += r;
      iunlock(f->ip);
      end_op();

      if(r != n1){
        // error from writei
        break;
      }
      i += r;
    }
    ret = (i == n ? n : -1);
  } else {
    panic("filewrite");
  }

  return ret;
}

