//
// driver for qemu's virtio disk device.
// uses qemu's mmio interface to virtio.
//
// qemu ... -drive file=fs.img,if=none,format=raw,id=x0 -device virtio-blk-device,drive=x0,bus=virtio-mmio-bus.0
//

#include "types.h"
#include "arch.h"
#include "defs.h"
#include "param.h"
#include "memlayout.h"
#include "spinlock.h"
#include "sleeplock.h"
#include "fs.h"
#include "buf.h"
#include "virtio.h"

// Maximum number of virtio disk devices we support
#define MAX_VIRTIO_DISKS 4

// Base addresses for multiple virtio devices
// These are the addresses that QEMU uses for virtio-mmio-bus.0, bus.1, etc.
#define VIRTIO1 0x10002000  // Second virtio device
#define VIRTIO2 0x10003000  // Third virtio device
#define VIRTIO3 0x10004000  // Fourth virtio device

// Array of addresses for different virtio devices
static uint64 virtio_addrs[MAX_VIRTIO_DISKS] = {
    VIRTIO0,   // 0x10001000 - First virtio device
    VIRTIO1,   // 0x10002000 - Second virtio device
    VIRTIO2,   // 0x10003000 - Third virtio device
    VIRTIO3    // 0x10004000 - Fourth virtio device
};

// the address of virtio mmio register r for a specific device.
#define R_DEV(dev, r) ((volatile uint32 *)(virtio_addrs[dev] + (r)))

// Per-device virtio disk structure
struct disk_device {
  // a set (not a ring) of DMA descriptors, with which the
  // driver tells the device where to read and write individual
  // disk operations. there are NUM descriptors.
  // most commands consist of a "chain" (a linked list) of a couple of
  // these descriptors.
  struct virtq_desc *desc;

  // a ring in which the driver writes descriptor numbers
  // that the driver would like the device to process.  it only
  // includes the head descriptor of each chain. the ring has
  // NUM elements.
  struct virtq_avail *avail;

  // a ring in which the device writes descriptor numbers that
  // the device has finished processing (just the head of each chain).
  // there are NUM used ring entries.
  struct virtq_used *used;

  // our own book-keeping.
  char free[NUM];  // is a descriptor free?
  uint16 used_idx; // we've looked this far in used[2..NUM].

  // track info about in-flight operations,
  // for use when completion interrupt arrives.
  // indexed by first descriptor index of chain.
  struct {
    struct buf *b;
    char status;
  } info[NUM];

  // disk command headers.
  // one-for-one with descriptors, for convenience.
  struct virtio_blk_req ops[NUM];

  struct spinlock vdisk_lock;

  int initialized;  // flag to track if this device is initialized
  int is_legacy;    // 1 = legacy mode (version 1), 0 = modern mode (version 2)
};

static struct disk_device disks[MAX_VIRTIO_DISKS];

int
virtio_disk_present(int dev)
{
  // Must match virtio_disk_rw(): dev=1 -> index 0, dev=2 -> index 1, ...
  int dev_index = dev - 1;

  if(dev_index < 0 || dev_index >= MAX_VIRTIO_DISKS)
    return 0;

