char *argv[] = { "sh", 0 };
char *runner_argv[] = { "basic_runner", 0 };
char *busybox_argv[] = { "busybox_runner", 0 };

int
main(void)
{
  int pid, wpid;

  if(open("/dev/console", O_RDWR) < 0){
    mknod("/dev/console", CONSOLE, 0);
    open("/dev/console", O_RDWR);
  }
  dup(0);  // stdout
  dup(0);  // stderr

  pid = fork();
  if(pid == 0){
    exec("/basic_runner", runner_argv);
    exit(0);
  }
  if(pid > 0)
    wait((int *)0);

  pid = fork();
  if(pid == 0){
    exec("/busybox_runner", busybox_argv);
    exit(0);
  }
  if(pid > 0)
    wait((int *)0);

  poweroff();

  for(;;){
    // printf("init: starting sh\n");
    // while(1);
    pid = fork();
    if(pid < 0){
      printf("init: fork failed\n");
      exit(1);
    }
    if(pid == 0){
      exec("/sh", argv);
      printf("init: exec sh failed\n");
      exit(1);
    }

    for(;;){
      // this call to wait() returns if the shell exits,
      // or if a parentless process exits.
      wpid = wait((int *) 0);
      if(wpid == pid){
        // the shell exited; restart it.
        break;
      } else if(wpid < 0){
        printf("init: wait returned an error\n");
        exit(1);
      } else {
        // it was a parentless process; do nothing.
      }
    }
  }
}

