// mark a descriptor as free.
static void
free_desc(int dev, int i)
{
  if(i >= NUM)
    panic("free_desc 1");
  if(disks[dev].free[i])
    panic("free_desc 2");
  disks[dev].desc[i].addr = 0;
  disks[dev].desc[i].len = 0;
  disks[dev].desc[i].flags = 0;
  disks[dev].desc[i].next = 0;
  disks[dev].free[i] = 1;
  wakeup(&disks[dev].free[0]);
}

// free a chain of descriptors.
static void
free_chain(int dev, int i)
{
  while(1){
    int flag = disks[dev].desc[i].flags;
    int nxt = disks[dev].desc[i].next;
    free_desc(dev, i);
    if(flag & VRING_DESC_F_NEXT)
      i = nxt;
    else
      break;
  }
}

// allocate three descriptors (they need not be contiguous).
// disk transfers always use three descriptors.
static int
alloc3_desc(int dev, int *idx)
{
  for(int i = 0; i < 3; i++){
    idx[i] = alloc_desc(dev);
    if(idx[i] < 0){
      for(int j = 0; j < i; j++)
        free_desc(dev, idx[j]);
      return -1;
    }
  }
  return 0;
}

void
virtio_disk_rw(struct buf *b, int write)
{
  // Determine which device this buffer corresponds to
  // Map device numbers to specific virtio instances
  // ROOTDEV (1) -> VIRTIO0 (index 0), DEV_SD (2) -> VIRTIO1 (index 1), etc.
  int dev_index = b->dev - 1;  // Convert device number to array index (0-based)

  // Check if the device index is valid and the device is initialized
  // If the device is not initialized, it may not exist in hardware
  if (dev_index < 0 || dev_index >= MAX_VIRTIO_DISKS) {
    panic("Device number out of range in virtio_disk_rw");
  }

  // If the device is not initialized, we could either panic or handle gracefully
  // For now, we'll allow access to uninitialized devices if they're within range
  // But we need to handle this differently - let's check if the device exists
  if (!disks[dev_index].initialized) {
    printf("Attempt to access uninitialized device %d (index %d)\n", b->dev, dev_index);
    panic("Uninitialized device in virtio_disk_rw");
  }

  uint64 sector = b->blockno * (BSIZE / 512);

  acquire(&disks[dev_index].vdisk_lock);

  // the spec's Section 5.2 says that legacy block operations use
  // three descriptors: one for type/reserved/sector, one for the
  // data, one for a 1-byte status result.

  // allocate the three descriptors.
  int idx[3];
  while(1){
    if(alloc3_desc(dev_index, idx) == 0) {
      break;
    }
    sleep(&disks[dev_index].free[0], &disks[dev_index].vdisk_lock);
  }

  // format the three descriptors.
  // qemu's virtio-blk.c reads them.

  struct virtio_blk_req *buf0 = &disks[dev_index].ops[idx[0]];

  if(write)
    buf0->type = VIRTIO_BLK_T_OUT; // write the disk
  else
    buf0->type = VIRTIO_BLK_T_IN; // read the disk
  buf0->reserved = 0;
  buf0->sector = sector;

  disks[dev_index].desc[idx[0]].addr = (uint64) buf0;
  disks[dev_index].desc[idx[0]].len = sizeof(struct virtio_blk_req);
  disks[dev_index].desc[idx[0]].flags = VRING_DESC_F_NEXT;
  disks[dev_index].desc[idx[0]].next = idx[1];

  disks[dev_index].desc[idx[1]].addr = (uint64) b->data;
  disks[dev_index].desc[idx[1]].len = BSIZE;
  if(write)
    disks[dev_index].desc[idx[1]].flags = 0; // device reads b->data
  else
    disks[dev_index].desc[idx[1]].flags = VRING_DESC_F_WRITE; // device writes b->data
  disks[dev_index].desc[idx[1]].flags |= VRING_DESC_F_NEXT;
  disks[dev_index].desc[idx[1]].next = idx[2];

  disks[dev_index].info[idx[0]].status = 0xff; // device writes 0 on success
  disks[dev_index].desc[idx[2]].addr = (uint64) &disks[dev_index].info[idx[0]].status;
  disks[dev_index].desc[idx[2]].len = 1;
  disks[dev_index].desc[idx[2]].flags = VRING_DESC_F_WRITE; // device writes the status
  disks[dev_index].desc[idx[2]].next = 0;

  // record struct buf for virtio_disk_intr().
  b->disk = 1;
  disks[dev_index].info[idx[0]].b = b;

  // tell the device the first index in our chain of descriptors.
  disks[dev_index].avail->ring[disks[dev_index].avail->idx % NUM] = idx[0];

  __sync_synchronize();

  // tell the device another avail ring entry is available.
  disks[dev_index].avail->idx += 1; // not % NUM ...

  __sync_synchronize();

  *R_DEV(dev_index, VIRTIO_MMIO_QUEUE_NOTIFY) = 0; // value is queue number

  // Wait for virtio_disk_intr() to say request has finished.
  while(b->disk == 1) {
    sleep(b, &disks[dev_index].vdisk_lock);
  }

  disks[dev_index].info[idx[0]].b = 0;
  free_chain(dev_index, idx[0]);

  release(&disks[dev_index].vdisk_lock);
}

void
virtio_disk_intr()
{
  // Process interrupts for all initialized devices
  for (int dev_index = 0; dev_index < MAX_VIRTIO_DISKS; dev_index++) {
    if (!disks[dev_index].initialized) {
      continue;
    }

    acquire(&disks[dev_index].vdisk_lock);

    // Check if this device has raised an interrupt
    uint32 int_status = *R_DEV(dev_index, VIRTIO_MMIO_INTERRUPT_STATUS);
    if (!(int_status & 0x3)) {
      release(&disks[dev_index].vdisk_lock);
      continue;
    }

    // the device won't raise another interrupt until we tell it
    // we've seen this interrupt, which the following line does.
    // this may race with the device writing new entries to
    // the "used" ring, in which case we may process the new
    // completion entries in this interrupt, and have nothing to do
    // in the next interrupt, which is harmless.
    *R_DEV(dev_index, VIRTIO_MMIO_INTERRUPT_ACK) = int_status & 0x3;

    __sync_synchronize();

    // the device increments disk.used->idx when it
    // adds an entry to the used ring.

    while(disks[dev_index].used_idx != disks[dev_index].used->idx){
      __sync_synchronize();
      int id = disks[dev_index].used->ring[disks[dev_index].used_idx % NUM].id;

      if(disks[dev_index].info[id].status != 0)
        panic("virtio_disk_intr status");

      struct buf *b = disks[dev_index].info[id].b;
      b->disk = 0;   // disk is done with buf
      wakeup(b);

      disks[dev_index].used_idx += 1;
    }

    release(&disks[dev_index].vdisk_lock);
  }
}

