// PCI virtio-blk driver for LoongArch QEMU virt machine.
// Uses PCIe ECAM (Enhanced Configuration Access Mechanism)
// at 0x20000000 to access PCI config space.

#include "types.h"
#include "arch.h"
#include "defs.h"
#include "param.h"
#include "memlayout.h"
#include "spinlock.h"
#include "sleeplock.h"
#include "fs.h"
#include "buf.h"
#include "virtio.h"

#ifdef __loongarch__
// On LoongArch, kalloc() returns DMWIN addresses (0x9000...).
// PCI devices need physical addresses for DMA.
static inline uint64
v2p(void *va)
{
  return (uint64)va & ~DMWIN_MASK;
}
#else
static inline uint64
v2p(void *va)
{
  return (uint64)va;
}
#endif

// QEMU loongarch64 virt machine DTB:
// pcie@20000000:
//   reg: addr=0x20000000, size=0x08000000
//   bus-range: 0-127
//   ranges:
//     IO:  PCI=0x00004000 -> CPU=0x0000000018004000, size=0x0000c000
//     MEM: PCI=0x40000000 -> CPU=0x0000000040000000, size=0x40000000

#define PCI_ECAM_BASE   0x20000000
#define PCI_MEM_BASE    0x40000000

// PCI config space access via ECAM
static inline uint32
pci_read32(uint32 bus, uint32 dev, uint32 func, uint32 off)
{
  uint64 addr = PCI_ECAM_BASE | (bus << 20) | (dev << 15) | (func << 12) | off;
  return *(volatile uint32 *)(addr | DMWIN_MASK);
}

static inline uint16
pci_read16(uint32 bus, uint32 dev, uint32 func, uint32 off)
{
  uint32 val = pci_read32(bus, dev, func, off & ~3);
  return (val >> ((off & 3) * 8)) & 0xFFFF;
}

static inline uint8
pci_read8(uint32 bus, uint32 dev, uint32 func, uint32 off)
{
  uint32 val = pci_read32(bus, dev, func, off & ~3);
  return (val >> ((off & 3) * 8)) & 0xFF;
}

static inline void
pci_write32(uint32 bus, uint32 dev, uint32 func, uint32 off, uint32 val)
{
  uint64 addr = PCI_ECAM_BASE | (bus << 20) | (dev << 15) | (func << 12) | off;
  *(volatile uint32 *)(addr | DMWIN_MASK) = val;
}

static inline void
pci_write16(uint32 bus, uint32 dev, uint32 func, uint32 off, uint16 val)
{
  uint32 old = pci_read32(bus, dev, func, off & ~3);
  uint32 mask = 0xFFFF << ((off & 3) * 8);
  uint32 new = (old & ~mask) | ((uint32)val << ((off & 3) * 8));
  pci_write32(bus, dev, func, off & ~3, new);
}

// PCI config space offsets
#define PCI_VENDOR_ID     0x00
#define PCI_DEVICE_ID     0x02
#define PCI_COMMAND       0x04
#define PCI_STATUS        0x06
#define PCI_REVISION      0x08
#define PCI_CLASS_PROG    0x09
#define PCI_CLASS_SUB     0x0A
#define PCI_CLASS_BASE    0x0B
#define PCI_BAR0          0x10
#define PCI_BAR1          0x14
#define PCI_CAP_PTR       0x34

// PCI command bits

virtio_disk_rw_large(int dev, uint64 sector, void *data, uint len, int write)
{
  int dev_index = dev - 1;

  if(dev_index < 0 || dev_index >= MAX_VIRTIO_DISKS)
    panic("virtio_disk_rw_large: bad dev");
  if(!disks[dev_index].initialized)
    panic("virtio_disk_rw_large: uninitialized");
