#define NELEM(x) (sizeof(x) / sizeof((x)[0]))

static const char *tests[] = {
  "brk", "chdir", "clone", "close", "dup2", "dup", "execve", "exit",
  "fork", "fstat", "getcwd", "getdents", "getpid", "getppid",
  "gettimeofday", "mkdir_", "mmap", "mount", "munmap", "openat", "open",
  "pipe", "read", "sleep", "times", "umount", "uname", "unlink",
  "wait", "waitpid", "write", "yield",
};

struct basic_dir {
  const char *dir;
  const char *parent;
};

static int
cd_any(const struct basic_dir *dirs, int ndirs)
{
  for(int i = 0; i < ndirs; i++){
    if(chdir(dirs[i].dir) == 0)
      return i;
  }
  return -1;
}

static int
run_basic_group(const char *group, const struct basic_dir *dirs, int ndirs)
{
  int dir_index;

  chdir("/");
  if((dir_index = cd_any(dirs, ndirs)) < 0)
    return 0;

  printf("#### OS COMP TEST GROUP START %s ####\n", group);

  for(int i = 0; i < NELEM(tests); i++){
    int pid, status = 0;
    int run_from_parent;
    char path[64];
    char *child_argv[] = { path, 0 };

    printf("Testing %s :\n", tests[i]);

    pid = fork();
    if(pid == 0){
      run_from_parent = 0;
      // chdir.c passes a 30-byte getcwd buffer; keep its cwd short.
      if(strcmp(tests[i], "chdir") == 0 && dirs[dir_index].parent &&
         chdir(dirs[dir_index].parent) == 0){
        run_from_parent = 1;
        strcpy(path, "basic/");
      } else {
        strcpy(path, "./");
      }
      strcpy(path + strlen(path), tests[i]);
      exec(path, child_argv);
      if(run_from_parent && chdir(dirs[dir_index].dir) == 0){
        strcpy(path, "./");
        strcpy(path + strlen(path), tests[i]);
        exec(path, child_argv);
      }
      child_argv[0] = (char *)tests[i];
      exec(tests[i], child_argv);
      printf("basic_runner: exec %s failed\n", tests[i]);
      exit(127);
    }
    if(pid < 0){
      printf("basic_runner: fork failed for %s\n", tests[i]);
      continue;
    }
    if(wait(&status) < 0)
      printf("basic_runner: wait failed for %s\n", tests[i]);
  }

  chdir("/");
  printf("#### OS COMP TEST GROUP END %s ####\n", group);
  return 1;
}

int
main(int argc, char **argv)
{
  static const struct basic_dir glibc_dirs[] = {
    { "/sdcard/glibc/basic", "/sdcard/glibc" },
    { "/glibc/basic", "/glibc" },
  };
  static const struct basic_dir musl_dirs[] = {
    { "/sdcard/musl/basic", "/sdcard/musl" },
    { "/musl/basic", "/musl" },
  };
  static const struct basic_dir plain_dirs[] = {
    { "/basic", "/" },
    { "/sdcard/basic", "/sdcard" },
    { "basic", "/" },
  };

  (void)argc;
  (void)argv;

  int ran = 0;
  ran += run_basic_group("basic-glibc", glibc_dirs, NELEM(glibc_dirs));
  ran += run_basic_group("basic-musl", musl_dirs, NELEM(musl_dirs));

  // Keep a fallback for locally-built single basic images that do not have
  // separate libc directories.
  if(ran == 0)
    run_basic_group("basic", plain_dirs, NELEM(plain_dirs));

  exit(0);
}

