static int
exists(char *path)
{
  int fd = open(path, O_RDONLY);
  if(fd < 0)
    return 0;
  close(fd);
  return 1;
}

static int
run_busybox_dir(char *group, char *dir)
{
  int pid, status = 0;
  char *argv[] = { "busybox", "sh", "./busybox_testcode.sh", 0 };

  if(chdir("/") < 0 || chdir(dir) < 0)
    return 0;
  if(!exists("busybox") || !exists("busybox_testcode.sh"))
    return 0;
  mkdir("busybox_work");
  unlink("busybox_work/busybox");
  unlink("busybox_work/busybox_testcode.sh");
  unlink("busybox_work/busybox_cmd.txt");
  unlink("busybox_work/sleep");
  link("busybox", "busybox_work/busybox");
  link("busybox_testcode.sh", "busybox_work/busybox_testcode.sh");
  link("busybox_cmd.txt", "busybox_work/busybox_cmd.txt");
  link("busybox", "busybox_work/sleep");
  if(chdir("busybox_work") < 0 || !exists("busybox") || !exists("busybox_testcode.sh"))
    return 0;

  printf("busybox_runner: running %s in %s/busybox_work\n", group, dir);
  pid = fork();
  if(pid == 0){
    exec("./busybox", argv);
    printf("busybox_runner: exec ./busybox failed\n");
    exit(127);
  }
  if(pid < 0){
    printf("busybox_runner: fork failed for %s\n", group);
    return 1;
  }
  if(wait(&status) < 0)
    printf("busybox_runner: wait failed for %s\n", group);
  else if(status != 0)
    printf("busybox_runner: %s exited with status %d\n", group, status);
  return 1;
}

static int
run_busybox_group(char *group, char **dirs, int ndirs)
{
  for(int i = 0; i < ndirs; i++){
    if(run_busybox_dir(group, dirs[i]))
      return 1;
  }
  return 0;
}

int
main(int argc, char **argv)
{
  char *glibc_dirs[] = { "/sdcard/glibc", "/glibc" };
  char *musl_dirs[] = { "/sdcard/musl", "/musl" };
  int ran = 0;

  (void)argc;
  (void)argv;

  ran += run_busybox_group("busybox-glibc", glibc_dirs, NELEM(glibc_dirs));
  ran += run_busybox_group("busybox-musl", musl_dirs, NELEM(musl_dirs));
  if(ran == 0)
    printf("busybox_runner: no busybox test directory found\n");
  exit(0);
}

