uint64
sys_newfstatat(void)
{
  int dirfd, flags;
  char path[MAXPATH];
  uint64 addr;
  struct file *f;
  struct inode *ip = 0;
  struct inode *start = 0;
  struct linux_kstat st;

  argint(0, &dirfd);
  argaddr(2, &addr);
  argint(3, &flags);
  if(argstr(1, path, MAXPATH) < 0)
    return -1;

  if(path[0] == 0 && (flags & AT_EMPTY_PATH)){
    if(argfd(0, 0, &f) < 0)
      return -1;
    if(f->type != FD_INODE && f->type != FD_DEVICE)
      return -1;
    ip = idup(f->ip);
  } else {
    if(path[0] != '/' && get_dirfd_inode(dirfd, &start) < 0)
      return -1;
    begin_op();
    ip = start ? nameiat(start, path) : namei(path);
    end_op();
    if(ip == 0)
      return LINUX_ENOENT;
  }

  ilock(ip);
  fill_linux_kstat(ip, &st);
  iunlockput(ip);
  if(copyout(myproc()->pagetable, addr, (char *)&st, sizeof(st)) < 0)
    return -1;
  return 0;
}

