  argaddr(1, &ubuf);
  argint(2, &len);

sys_getdents64(void)
{
  struct file *f;
  struct dirent de;
  uint64 ubuf;
  int len;
  int total = 0;

  argaddr(1, &ubuf);
  argint(2, &len);
  if(len <= 0)
    return -1;
  if(argfd(0, 0, &f) < 0)
    return -1;
  if(f->type != FD_INODE)
    return -1;

  ilock(f->ip);
  if(f->ip->type != T_DIR){
    iunlock(f->ip);
    return -1;
  }
  iunlock(f->ip);

  for(;;){
    char rec[128];
    int namelen, reclen;
    uchar dtype = DT_UNKNOWN;

    ilock(f->ip);
    int r = readi(f->ip, 0, (uint64)&de, f->off, sizeof(de));
    iunlock(f->ip);
    if(r == 0)
      break;
    if(r != sizeof(de))
      return total > 0 ? total : -1;
    f->off += sizeof(de);
    if(de.inum == 0)
      continue;

    namelen = kstrnlen(de.name, DIRSIZ);
    reclen = (19 + namelen + 1 + 7) & ~7;
    if(reclen > sizeof(rec))
      return total > 0 ? total : -1;
    if(total + reclen > len){
      f->off -= sizeof(de);
      break;
    }

    memset(rec, 0, sizeof(rec));
    *(uint64 *)(rec + 0) = de.inum;
    *(long *)(rec + 8) = f->off;
    *(ushort *)(rec + 16) = reclen;
    *(uchar *)(rec + 18) = dtype;
    memmove(rec + 19, de.name, namelen);
    rec[19 + namelen] = 0;

    if(copyout(myproc()->pagetable, ubuf + total, rec, reclen) < 0)
      return total > 0 ? total : -1;
    total += reclen;
  }
  return total;
}

