openat_impl(int dirfd, char *path, int omode)
{
  int fd;
  int accmode = omode & 3;
  int trunc = omode & O_LINUX_TRUNC;
  int append = omode & O_LINUX_APPEND;
  struct file *f;
  struct inode *ip;
  struct inode *start = 0;

  if(path[0] != '/' && get_dirfd_inode(dirfd, &start) < 0)
    return -1;

  begin_op();

  if(omode & O_ANY_CREATE){
    ip = createat(start, path, T_FILE, 0, 0);
    if(ip == 0){
      end_op();
      return -1;
    }
    if(ip->type == T_DIR){
      iunlockput(ip);
      end_op();
      return -1;
    }
  } else {
    ip = start ? nameiat(start, path) : namei(path);
    if(ip == 0){
      end_op();
      return LINUX_ENOENT;
    }
    ilock(ip);
    if((omode & O_DIRECTORY) && ip->type != T_DIR){
      iunlockput(ip);
      end_op();
      return -1;
    }
    if(ip->type == T_DIR && accmode != O_RDONLY){
      iunlockput(ip);
      end_op();
      return -1;
    }
  }

  if(ip->type == T_DEVICE && (ip->major < 0 || ip->major >= NDEV)){
    iunlockput(ip);
    end_op();
    return -1;
  }

  if((f = filealloc()) == 0 || (fd = fdalloc(f)) < 0){
    if(f)
      fileclose(f);
    iunlockput(ip);
    end_op();
    return -1;
  }

  if(ip->type == T_DEVICE){
    f->type = FD_DEVICE;
    f->major = ip->major;
  } else {
    f->type = FD_INODE;
    f->off = 0;
  }
  f->ip = ip;
  f->readable = accmode != O_WRONLY;
  f->writable = accmode == O_WRONLY || accmode == O_RDWR;
  f->append = append != 0;

  if(trunc && ip->type == T_FILE)
    itrunc(ip);

  iunlock(ip);
  end_op();
  return fd;
}

