// Paths

// Copy the next path element from path into name.
// Return a pointer to the element following the copied one.
// The returned path has no leading slashes,
// so the caller can check *path=='\0' to see if the name is the last one.
// If no name to remove, return 0.
//
// Examples:
//   skipelem("a/bb/c", name) = "bb/c", setting name = "a"
//   skipelem("///a//bb", name) = "bb", setting name = "a"
//   skipelem("a", name) = "", setting name = "a"
//   skipelem("", name) = skipelem("////", name) = 0
//
static char*
skipelem(char *path, char *name)
{
  char *s;
  int len;

  while(*path == '/')
    path++;
  if(*path == 0)
    return 0;
  s = path;
  while(*path != '/' && *path != 0)
    path++;
  len = path - s;
  if(len >= DIRSIZ)
    memmove(name, s, DIRSIZ);
  else {
    memmove(name, s, len);
    name[len] = 0;
  }
  while(*path == '/')
    path++;
  return path;
}

// Look up and return the inode for a path name.
// If parent != 0, return the inode for the parent and copy the final
// path element into name, which must have room for DIRSIZ bytes.
// Must be called inside a transaction since it calls iput().
static struct inode*
namex(char *path, int nameiparent, char *name, struct inode *start)
{
  struct inode *ip, *next;
  uint rootino = ROOTINO;
  uint dev = ROOTDEV;

  // Check for /sdcard/ prefix - use DEV_SD for sdcard
  if (strncmp(path, "/sdcard", 7) == 0 &&
    (path[7] == '\0' || path[7] == '/')) {
    dev = DEV_SD;
    if (ext4_is_ext4(dev)) {
      rootino = EXT4_ROOT_INO;
    }
    // 去掉/sdcard前缀
    path += 7;
    // // 跳过可能存在的额外斜杠
    // while(*path == '/')
    //   path++;
    // // 如果去掉前缀后路径为空，则指向根目录
    // if(*path == 0) {
    //   path = "/";
    // }
  } else {
    // For / path, check if fs.ext4.img is mounted as root
    // 检查EXT4文件系统是否挂载在专用设备上，如果是则使用该设备
    if (ext4_is_ext4(DEV_FS_EXT4)) {
      dev = DEV_FS_EXT4;
      rootino = EXT4_ROOT_INO;
    } else if (ext4_is_ext4(ROOTDEV)) {
      // 否则检查根设备是否为EXT4文件系统
      dev = ROOTDEV;
      rootino = EXT4_ROOT_INO;
    }
  }

  // 根据路径是绝对路径还是相对路径，获取起始inode
  if(*path == '/'|| *path == '\0')
    ip = iget(dev, rootino);  // 绝对路径：从根目录开始
  else
    ip = idup(myproc()->cwd);  // 相对路径：从当前工作目录开始

  // 遍历路径中的每个目录项
  if(start && *path != '/' && *path != '\0'){
    iput(ip);
    ip = idup(start);
  }

  while((path = skipelem(path, name)) != 0){
    // printf("namex: looking for '%s' in inode %d\n", name, ip->inum);
    ilock(ip);  // 锁定当前inode
    if(ip->type != T_DIR){  // 检查是否为目录类型
      iunlockput(ip);
      return 0;
    }
    if(nameiparent && *path == '\0'){
      // 如果需要返回父目录，且已到达路径末尾，则提前停止
      iunlock(ip);
      return ip;
    }
    if((next = dirlookup(ip, name, 0)) == 0){  // 在目录中查找下一个路径元素
      // printf("namex: '%s' not found in inode %d\n", name, ip->inum);
      iunlockput(ip);
      return 0;
    }
    // printf("namex: '%s' -> inode %d\n", name, next->inum);
    iunlockput(ip);  // 解锁并释放当前inode
    ip = next;  // 移动到下一个inode继续遍历
  }
  if(nameiparent){  // 如果需要返回父目录但未找到
    iput(ip);
    return 0;
  }
  return ip;  // 返回最终找到的inode
}

struct inode*
namei(char *path)
{
  char name[DIRSIZ];
  return namex(path, 0, name, 0);
}

struct inode*
nameiparent(char *path, char *name)
{
  return namex(path, 1, name, 0);
}

struct inode*
nameiat(struct inode *start, char *path)
{
  char name[DIRSIZ];
  return namex(path, 0, name, start);
}

struct inode*
nameiparentat(struct inode *start, char *path, char *name)
{
  return namex(path, 1, name, start);
}
